</div> <div class="recent-post-content"> <h4> <a href="/blog-post.php?slug=<?php echo urlencode($recent['slug']?? '');?>"> <?php echo htmlspecialchars($recent['title']);?> </a> </h4> <div class="recent-post-meta"> <?php echo date('M j, Y', strtotime($recent['publish_date']));?> </div> </div> </li> <?php endforeach;?> </ul> </div> <!-- Newsletter Widget --> <div class="sidebar-widget"> <h3 class="widget-title">Security Insights Newsletter</h3> <p style="margin-bottom: 20px; color: #555;">Get monthly security tips and industry updates directly to your inbox.</p> <form class="newsletter-form" id="blog-newsletter" method="POST" action="/api/newsletter.php"> <input type="email" class="newsletter-input" name="email" placeholder="Your email address" required> <button type="submit" class="newsletter-btn">Subscribe</button> </form> </div> <!-- Popular Tags Widget --> <div class="sidebar-widget"> <h3 class="widget-title">Popular Tags</h3> <div class="tags-cloud"> <a href="/blog?search=security+tips" class="tag">Security Tips</a> <a href="/blog?search=alarm+response" class="tag">Alarm Response</a> <a href="/blog?search=CCTV" class="tag">CCTV</a> <a href="/blog?search=access+control" class="tag">Access Control</a> <a href="/blog?search=risk+assessment" class="tag">Risk Assessment</a> <a href="/blog?search=emergency" class="tag">Emergency</a> <a href="/blog?search=training" class="tag">Training</a> <a href="/blog?search=compliance" class="tag">Compliance</a> <a href="/blog?search=technology" class="tag">Technology</a> <a href="/blog?search=safety" class="tag">Safety</a> </div> </div> </aside> </div> </section> <!-- Blog CTA Section --> <section class="blog-cta"> <div class="container"> <h2>Need Professional Security Advice?</h2> <p>Our security experts are available to provide personalized consultations and site assessments for your business or residential property.</p> <div class="hero-buttons"> <a href="tel:0370648292" class="cta-button">Call for Consultation</a> <a href="/contact" class="secondary-button">Request Site Assessment</a> </div> </div> </section> <!-- Footer --> <!-- Dark Mode Toggle Button --> <button id="themeToggle" class="theme-button" style="position: fixed; bottom: 20px; right: 20px; z-index: 1000;"> <i class="fas fa-moon">
</i> Dark Mode </button> <!-- JavaScript for Blog Functionality --> <script> // Dark Mode Functionality function setCookie(name, value, days) { const date = new Date(); date.setTime(date.getTime + (days * 24 * 60 * 60 * 1000)); const expires = "expires=" + date.toUTCString; document.cookie = `${name}=${value};${expires};path=/`; } function getCookie(name) { const cookies = document.cookie.split(';'); for (let cookie of cookies) { const [cookieName, cookieValue] = cookie.trim.split('='); if (cookieName === name) return cookieValue; } return null; } // Theme toggle functionality const themeToggle = document.getElementById('themeToggle'); themeToggle.addEventListener('click', function { document.body.classList.toggle('dark-theme'); if (document.body.classList.contains('dark-theme')) { setCookie('theme', 'dark', 30); themeToggle.innerHTML = '<i class="fas fa-sun">
</i> Light Mode'; } else { setCookie('theme', 'light', 30); themeToggle.innerHTML = '<i class="fas fa-moon">
</i> Dark Mode'; } }); // Apply theme on load window.addEventListener('DOMContentLoaded',  => { const theme = getCookie('theme') || 'light'; if (theme === 'dark') { document.body.classList.add('dark-theme'); themeToggle.innerHTML = '<i class="fas fa-sun">
</i> Light Mode'; } // Set active nav link const currentPage = window.location.pathname; const navLinks = document.querySelectorAll('nav a'); navLinks.forEach(link => { if (link.getAttribute('href') === currentPage) { link.classList.add('active'); } }); // Blog Search Functionality (client-side filtering) const searchInput = document.querySelector('.blog-search-input'); const blogPosts = document.querySelectorAll('.blog-post-card'); if (searchInput &&!<?php echo $search? 'true': 'false';?>) { searchInput.addEventListener('input', function { const searchTerm = this.value.toLowerCase.trim; if (searchTerm.length === 0) { blogPosts.forEach(post => { post.style.display = 'block'; }); return; } blogPosts.forEach(post => { const title = post.querySelector('h3').textContent.toLowerCase; const excerpt = post.querySelector('p').textContent.toLowerCase; const category = post.getAttribute('data-category'); if (title.includes(searchTerm) || excerpt.includes(searchTerm) || category.includes(searchTerm)) { post.style.display = 'block'; } else { post.style.display = 'none'; } }); }); } // Newsletter Form Submission const newsletterForm = document.getElementById('blog-newsletter'); if (newsletterForm) { newsletterForm.addEventListener('submit', function(e) { e.preventDefault; const emailInput = this.querySelector('input[type="email"]'); const submitBtn = this.querySelector('button'); const originalText = submitBtn.textContent; submitBtn.textContent = 'Subscribing...'; submitBtn.disabled = true; // AJAX submission fetch(this.action, { method: 'POST', headers: { 'Content-Type': 'application/x-www-form-urlencoded', }, body: new URLSearchParams({ email: emailInput.value }) }).then(response => response.json).then(data => { if (data.success) { submitBtn.textContent = 'Subscribed!'; submitBtn.style.background = '#4CAF50'; emailInput.value = ''; const successMsg = document.createElement('div'); successMsg.style.color = '#4CAF50'; successMsg.style.marginTop = '10px'; successMsg.style.fontSize = '0.9rem'; successMsg.textContent = data.message || 'Thank you for subscribing!'; this.appendChild(successMsg); setTimeout( => { successMsg.remove; }, 5000); } else { alert(data.message || 'Subscription failed.'); } }).catch(error => { console.error('Error:', error); alert('Subscription failed. Please try again.'); }).finally( => { setTimeout( => { submitBtn.textContent = originalText; submitBtn.disabled = false; submitBtn.style.background = ''; }, 2000); }); }); } // Category Filtering const categoryLinks = document.querySelectorAll('.categories-list a'); categoryLinks.forEach(link => { // Active state based on current category const currentUrl = new URL(window.location.href); const currentCategory = currentUrl.searchParams.get('category'); const linkCategory = link.getAttribute('href').split('category=')[1]; if ((!currentCategory && link.getAttribute('href') === 'blog.php') || (currentCategory && linkCategory === currentCategory)) { link.classList.add('active'); } }); // Blog Post Animation on Scroll const observerOptions = { threshold: 0.1, rootMargin: '0px 0px -50px 0px' }; const observer = new IntersectionObserver((entries) => { entries.forEach((entry, index) => { if (entry.isIntersecting) { setTimeout( => { entry.target.style.opacity = '1'; entry.target.style.transform = 'translateY(0)'; }, index * 100); } }); }, observerOptions); blogPosts.forEach((post, index) => { post.style.opacity = '0'; post.style.transform = 'translateY(20px)'; post.style.transition = 'opacity 0.5s ease, transform 0.5s ease'; observer.observe(post); }); // Header scroll effect window.addEventListener('scroll', function { const header = document.querySelector('header'); if (window.scrollY > 50) { header.style.padding = '10px 5%'; header.style.boxShadow = '0 5px 20px rgba(0, 0, 0, 0.1)'; } else { header.style.padding = '15px 5%'; header.style.boxShadow = '0 2px 15px rgba(0, 0, 0, 0.1)'; } }); // Auto-update blog posts every 5 minutes let lastUpdate = Date.now; const updateInterval = 5 * 60 * 1000; function checkForUpdates { fetch('/api/check-updates.php?last_update=' + lastUpdate).then(response => response.json).then(data => { if (data.success && data.new_posts && data.new_posts.length > 0) { addNewPosts(data.new_posts); lastUpdate = Date.now; showUpdateNotification(data.new_posts.length); } }).catch(error => console.error('Update check failed:', error)); } function escapeHtml(value) { const div = document.createElement('div'); div.textContent = value?? ''; return div.innerHTML; } function addNewPosts(posts) { const container = document.getElementById('blog-posts-container'); posts.forEach(post => { const safeCategory = escapeHtml(post.category); const safeTitle = escapeHtml(post.title); const safeExcerpt = escapeHtml(post.excerpt); const safeAuthorName = escapeHtml(post.author_name); const safeAuthorTitle = escapeHtml(post.author_title); const safeFeaturedImage = encodeURI(post.featured_image || ''); const safeSlug = encodeURIComponent(post.slug || ''); const article = document.createElement('article'); article.className = 'blog-post-card'; article.setAttribute('data-category', safeCategory); // Generate author initials let author_initials = ''; if (post.author_name) { const names = post.author_name.split(' '); names.forEach(name => { author_initials += name.charAt(0).toUpperCase; }); } article.innerHTML = ` <div class="post-image" style="background-image: url('${safeFeaturedImage}');"> <span class="category-tag">${safeCategory}</span> <span class="new-badge" style="position: absolute; top: 15px; right: 15px; background: var(--secondary); color: white; padding: 4px 10px; border-radius: 20px; font-size: 0.7rem; font-weight: 600;">NEW</span> </div> <div class="post-card-content"> <h3>${safeTitle}</h3> <p>${safeExcerpt}</p> <div class="card-meta"> <div class="author"> <div class="author-avatar">${author_initials}</div> <div class="author-info"> <h4>${safeAuthorName}</h4> <span>${safeAuthorTitle}</span> </div> </div> <a href="/blog/post/${safeSlug}" class="read-more-btn"> Read More <i class="fas fa-arrow-right">
</i> </a> </div> </div> `; // Add with animation article.style.opacity = '0'; article.style.transform = 'translateY(20px)'; container.insertBefore(article, container.firstChild); // Animate in setTimeout( => { article.style.transition = 'opacity 0.5s ease, transform 0.5s ease'; article.style.opacity = '1'; article.style.transform = 'translateY(0)'; }, 100); }); } function showUpdateNotification(count) { const notification = document.createElement('div'); notification.className = 'update-notification'; notification.innerHTML = ` <span>${count} new post${count > 1? 's': ''} added</span> <button onclick="this.parentElement.remove">Ã—</button> `; notification.style.cssText = ` position: fixed; top: 100px; right: 20px; background: var(--primary); color: white; padding: 15px 20px; border-radius: 10px; box-shadow: 0 5px 20px rgba(0,0,0,0.2); z-index: 10000; display: flex; align-items: center; gap: 15px; animation: slideIn 0.3s ease; `; // Add keyframe animation const style = document.createElement('style'); style.textContent = ` @keyframes slideIn { from { transform: translateX(100%); opacity: 0; } to { transform: translateX(0); opacity: 1; } } @keyframes slideOut { from { transform: translateX(0); opacity: 1; } to { transform: translateX(100%); opacity: 0; } } `; document.head.appendChild(style); document.body.appendChild(notification); // Auto-remove after 5 seconds setTimeout( => { if (notification.parentNode) { notification.style.animation = 'slideOut 0.3s ease'; setTimeout( => notification.remove, 300); } }, 5000); } // Start update checker setInterval(checkForUpdates, updateInterval); // Check on page load window.addEventListener('load', checkForUpdates); }); </script>


